     @Service
     public class RecommendationService {
         static final String CACHE_NAME = "recommendations";
         private final RecommendationRepository recommendationRepository;
         private final ResourceRepository resourceRepository;
         private final StringRedisTemplate redisTemplate;
         private final String cacheKeyPrefix;  // computed once at startup

         public RecommendationService(RecommendationRepository recommendationRepository,
                                      ResourceRepository resourceRepository,
                                      StringRedisTemplate redisTemplate,
                                      RedisCacheConfiguration cacheConfiguration) {
             this.recommendationRepository = recommendationRepository;
             this.resourceRepository = resourceRepository;
             this.redisTemplate = redisTemplate;
             this.cacheKeyPrefix = cacheConfiguration.getKeyPrefixFor(CACHE_NAME);
         }

         @Transactional
         public void generateRecommendation(AssessmentTriggerDTO trigger) {
             List<Resource> resources = resourceRepository.findByCompetencyIdAndLevelOrUnclassified(
                     trigger.getCompetencyId(), trigger.getLevel());
             if (resources.isEmpty()) throw new NotFoundException(...);
             recommendationRepository.deleteByUserIdAndCompetencyId(
                     trigger.getUserId(), trigger.getCompetencyId());
             // ... saveAll recommendations ...
             Long userId = trigger.getUserId();
             TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
                 @Override public void afterCommit() { evictUserCache(userId); }
             });
         }

         @Cacheable(value = CACHE_NAME, keyGenerator = "recommendationKeyGenerator")
         public List<RecommendationDTO> getUserRecommendations(Long userId, Pageable pageable) { ... }

         @Transactional
         public void deleteRecommendation(Long id) {
             Recommendation rec = recommendationRepository.findById(id)
                     .orElseThrow(() -> new NotFoundException(...));
             recommendationRepository.delete(rec);
             Long userId = rec.getUserId();
             TransactionSynchronizationManager.registerSynchronization(new TransactionSynchronization() {
                 @Override public void afterCommit() { evictUserCache(userId); }
             });
         }

         private void evictUserCache(Long userId) {
             Set<String> keys = scanKeys(cacheKeyPrefix + userId + ":*");
             if (!keys.isEmpty()) redisTemplate.delete(keys);
         }

         private Set<String> scanKeys(String pattern) {
             return redisTemplate.execute((RedisCallback<Set<String>>) connection -> {
                 Set<String> result = new HashSet<>();
                 ScanOptions opts = ScanOptions.scanOptions().match(pattern).count(200).build();
                 Cursor<byte[]> cursor = connection.keyCommands().scan(opts);
                 try {
                     while (cursor.hasNext())
                         result.add(new String(cursor.next(), StandardCharsets.UTF_8));
                 } finally {
                     try { cursor.close(); } catch (Exception ignored) {}
                 }
                 return result;
             });
         }
     }
     ```

