     @Bean("recommendationKeyGenerator")
     public KeyGenerator recommendationKeyGenerator() {
         return (target, method, params) -> {
             Long userId = (Long) params[0];
             Pageable pageable = (Pageable) params[1];
             String sortKey = StreamSupport.stream(pageable.getSort().spliterator(), false)
                 .map(o -> o.getProperty() + "_" + o.getDirection())
                 .sorted().collect(joining(","));
             return userId + ":" + pageable.getPageNumber() + ":" + pageable.getPageSize() + ":" + sortKey;
         };
     }
